var judgeCircle = function(moves) {
    let x = 0, y = 0;
    for (const c of moves) {
        if (c === 'L') x -= 1;
        else if (c === 'R') x += 1;
        else if (c === 'U') y += 1;
        else y -= 1;
    }
    return x === 0 && y === 0;
};
